            onLogout={handleLogout} 
            settings={settings}
        />
      )}

      {/* JOS JIS SCHEDULE POPUP MODAL */}
      {showBlockedModal && (
          <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-in fade-in duration-300">
