                    onClick={onComplete}
                    className="w-full text-white font-bold py-3.5 rounded-xl shadow-lg transition transform hover:-translate-y-1 hover:shadow-xl active:scale-95"
                    style={{ backgroundColor: themeColor }}
                  >
                      Lanjut ke Mata Pelajaran Lain
                  </button>
              </div>
          </div>
