                  id: `imp-${idx}-${Date.now()}`,
                  type: finalType,
                  text: text || 'Soal',
                  imgUrl: img && String(img).startsWith('http') ? img : undefined,
                  options: [oa || '', ob || '', oc || '', od || ''],
